/*completed */
import React, { useEffect, useRef, useState } from 'react'
import toast from 'react-hot-toast';
import Axios from '../utils/Axios';
import SummaryApi from '../common/SummaryApi';
import AxiosToastError from '../utils/AxiosToastError';
import { Link, useLocation, useNavigate } from 'react-router-dom';

const OtpVerification = () => {
    const [data, setData] = useState(["", "", "", "", "", ""]);
    const [isLoading, setIsLoading] = useState(false);
    const [shake, setShake] = useState(false);
    const [timer, setTimer] = useState(30);
    const [canResend, setCanResend] = useState(false);

    const navigate = useNavigate();
    const inputRef = useRef([]);
    const location = useLocation();

    // ---------------------- REDIRECT IF NO EMAIL ----------------------
    useEffect(() => {
        if (!location?.state?.email) {
            navigate("/forgot-password");
        }
    }, []);

    // ---------------------- COUNTDOWN TIMER ----------------------
    useEffect(() => {
        if (timer === 0) {
            setCanResend(true);
            return;
        }

        const interval = setInterval(() => {
            setTimer(prev => prev - 1);
        }, 1000);

        return () => clearInterval(interval);
    }, [timer]);

    const valideValue = data.every(el => el);

    // ---------------------- HANDLE CHANGE ----------------------
    const handleChange = (value, index) => {
        let newData = [...data];

        if (value.length === 6) {
            newData = value.split("").slice(0, 6);
            setData(newData);
            inputRef.current[5]?.focus();
            return;
        }

        newData[index] = value.slice(-1);
        setData(newData);

        if (value && index < 5) {
            inputRef.current[index + 1]?.focus();
        }
    };

    // ---------------------- KEY HANDLING ----------------------
    const handleKeyDown = (e, index) => {
        const key = e.key;

        if (key === "Backspace" && !data[index] && index > 0) {
            inputRef.current[index - 1]?.focus();
        }

        if (key === "ArrowLeft" && index > 0) {
            inputRef.current[index - 1]?.focus();
        }

        if (key === "ArrowRight" && index < 5) {
            inputRef.current[index + 1]?.focus();
        }
    };

    // ---------------------- HANDLE PASTE ----------------------
    const handlePaste = (e) => {
        const pasted = e.clipboardData.getData("text").trim();

        if (/^[0-9]{6}$/.test(pasted)) {
            setData(pasted.split(""));
            inputRef.current[5]?.focus();
        }

        e.preventDefault();
    };

    // ---------------------- RESEND OTP ----------------------
    const handleResend = async () => {
        try {
            const res = await Axios({
                ...SummaryApi.forgot_password,
                data: { email: location?.state?.email }
            });

            toast.success("OTP Sent Again!");
            setTimer(30);
            setCanResend(false);
        } catch (error) {
            AxiosToastError(error);
        }
    };

    // ---------------------- VERIFY OTP ----------------------
    const handleSubmit = async (e) => {
        e.preventDefault();

        setIsLoading(true);

        try {
            const response = await Axios({
                ...SummaryApi.forgot_password_otp_verification,
                data: {
                    otp: data.join(""),
                    email: location?.state?.email
                }
            });

            setIsLoading(false);

            if (response.data.error) {
                toast.error(response.data.message);

                // Shake animation
                setShake(true);
                setTimeout(() => setShake(false), 500);

                return;
            }

            if (response.data.success) {
                toast.success(response.data.message);
                setData(["", "", "", "", "", ""]);

                navigate("/reset-password", {
                    state: {
                        data: response.data,
                        email: location?.state?.email
                    }
                });
            }

        } catch (error) {
            setIsLoading(false);
            AxiosToastError(error);
        }
    };

    return (
        <section className='w-full container mx-auto px-2'>
            <div className='bg-white my-4 w-full max-w-lg mx-auto rounded-2xl p-7'>
                <p className='font-semibold text-lg'>Enter OTP</p>

                <form className='grid gap-4 py-4' onSubmit={handleSubmit}>
                    <div className='grid gap-1'>
                        <label htmlFor='otp'>Enter Your OTP :</label>

                        <div
                            className={`flex items-center gap-2 justify-between mt-3 ${shake ? "animate-shake" : ""}`}
                            onPaste={handlePaste}
                        >
                            {data.map((value, index) => (
                                <input
                                    key={index}
                                    type='text'
                                    maxLength={1}
                                    value={value}
                                    ref={ref => (inputRef.current[index] = ref)}
                                    onChange={(e) => handleChange(e.target.value, index)}
                                    onKeyDown={(e) => handleKeyDown(e, index)}
                                    className='bg-blue-50 w-full max-w-16 p-2 border rounded-2xl outline-none 
                                    focus:border-green-200 text-center font-semibold text-lg'
                                />
                            ))}
                        </div>
                    </div>

                    <button
                        disabled={!valideValue || isLoading}
                        className={`flex justify-center items-center gap-2
                        ${valideValue ? "bg-green-800 hover:bg-green-700" : "bg-gray-500"}
                        text-white py-2 rounded font-semibold my-3 tracking-wide`}
                    >
                        {isLoading ? (
                            <span className="spinner border-2 w-5 h-5 rounded-full border-t-transparent animate-spin"></span>
                        ) : (
                            "Verify OTP"
                        )}
                    </button>
                </form>

                {/* TIMER + RESEND */}
                <div className='flex justify-between items-center py-2'>
                    <p className='text-gray-600'>
                        {canResend ? "Didn't receive OTP?" : `Resend in ${timer}s`}
                    </p>

                    <button
                        onClick={handleResend}
                        disabled={!canResend}
                        className={`font-semibold ${canResend ? "text-green-700" : "text-gray-400"}`}
                    >
                        Resend OTP
                    </button>
                </div>

                <p>
                    Already have account?{" "}
                    <Link to={"/login"} className='font-semibold text-green-700 hover:text-green-800'>
                        Login
                    </Link>
                </p>
            </div>

            {/* ANIMATIONS */}
            <style>{`
                .animate-shake {
                    animation: shake 0.3s linear;
                }
                @keyframes shake {
                    0% { transform: translateX(0); }
                    25% { transform: translateX(-4px); }
                    50% { transform: translateX(4px); }
                    75% { transform: translateX(-4px); }
                    100% { transform: translateX(0); }
                }
                .spinner {
                    border-radius: 50%;
                }
            `}</style>
        </section>
    );
};

export default OtpVerification;

import React, { useEffect, useState } from 'react'
import SummaryApi from '../common/SummaryApi'
import AxiosToastError from '../utils/AxiosToastError'
import Axios from '../utils/Axios'

const Product = () => {

  const [productData, setProductData] = useState([])
  const [page, setPage] = useState(1)
  const [loading, setLoading] = useState(false)

  const fetchProductData = async () => {
    try {
      setLoading(true)
      const response = await Axios({
        ...SummaryApi.getProduct,
        data: {
          page: page,
        }
      })

      const { data: responseData } = response

      if (responseData?.success) {
        setProductData(responseData.data || [])
      }

    } catch (error) {
      AxiosToastError(error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchProductData()
  }, [page])

  return (
    <div className='p-4'>

      <h2 className='text-xl font-semibold mb-3'>Products</h2>

      {loading && (
        <p className='text-neutral-500'>Loading...</p>
      )}

      {!loading && productData.length === 0 && (
        <p className='text-neutral-500'>No products found</p>
      )}

      {!loading && productData.length > 0 && (
        <div className='grid gap-3'>
          {productData.map((item, index) => (
            <div
              key={item?._id || index}
              className='border p-3 rounded bg-white shadow'
            >
              {item?.name || "Untitled Product"}
            </div>
          ))}
        </div>
      )}

    </div>
  )
}

export default Product

import React, { useEffect, useState } from 'react'
import SummaryApi from '../common/SummaryApi'
import AxiosToastError from '../utils/AxiosToastError'
import Axios from '../utils/Axios'
import Loading from '../components/Loading'
import AdminProduct from '../components/AdminProduct'
import { IoSearchOutline } from "react-icons/io5"
import { IoRefresh } from "react-icons/io5";

const ProductAdmin = () => {
  const [productData, setProductData] = useState([])
  const [page, setPage] = useState(1)
  const [loading, setLoading] = useState(false)
  const [totalPageCount, setTotalPageCount] = useState(1)
  const [search, setSearch] = useState("")

  const fetchProductData = async () => {
    try {
      setLoading(true)
      const response = await Axios({
        ...SummaryApi.getProduct,
        data: {
          page: page,
          limit: 12,
          search: search
        }
      })

      const { data: responseData } = response


      if (responseData.success) {
        setTotalPageCount(responseData.totalNoPage)
        setProductData(responseData.data || [])
      }
    } catch (error) {
      AxiosToastError(error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchProductData()
  }, [page])

  const handleNext = () => {
    if (page < totalPageCount) setPage(prev => prev + 1)
  }

  const handlePrevious = () => {
    if (page > 1) setPage(prev => prev - 1)
  }

  const handleOnChange = (e) => {
    const { value } = e.target
    setSearch(value)
    setPage(1)
  }

  useEffect(() => {
    const interval = setTimeout(() => {
      fetchProductData()
    }, 300)

    return () => clearTimeout(interval)
  }, [search])

  return (
    <section className=''>
      <div className='p-4 bg-white shadow-md flex items-center justify-between gap-4'>
        <h2 className='font-black text-xl text-gray-900 uppercase tracking-tighter'>Products</h2>

        <div className='h-11 min-w-24 max-w-md w-full ml-auto bg-gray-50 px-4 flex items-center gap-3 rounded-xl border border-gray-100 focus-within:border-gray-900 transition-all'>
          <IoSearchOutline size={20} className='text-gray-400' />
          <input
            type='text'
            placeholder='Search product here...'
            className='h-full w-full outline-none bg-transparent text-sm font-medium'
            value={search}
            onChange={handleOnChange}
          />
        </div>
      </div>

      <div className='p-4 bg-blue-50 min-h-[70vh] flex flex-col'>
        {loading ? (
            <div className='flex-1 flex items-center justify-center'>
                <Loading />
            </div>
        ) : (
            <>
                <div className='min-h-[55vh]'>
                <div className='grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4'>
                    {productData && productData.length > 0 ? (
                    productData.map((p, index) => (
                        <AdminProduct key={p._id || index} data={p} fetchProductData={fetchProductData} />
                    ))
                    ) : (
                    <p className='text-center font-bold mt-[30vh] col-span-full text-gray-500'>No products found</p>
                    )}
                </div>
                </div>

                <div className='flex justify-between my-4'>
                <button onClick={handlePrevious} className="border border-green-300 px-4 py-1 hover:text-white hover:bg-green-400">Previous</button>
                <button className='w-full bg-slate-100'>{page}/{totalPageCount}</button>
                <button onClick={handleNext} className="border border-green-300 px-4 py-1 hover:text-white hover:bg-green-400">Next</button>
                </div>
            </>
        )}
      </div>
    </section>
  )
}

export default ProductAdmin

import React, { useEffect, useRef, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useSelector } from 'react-redux'
import SummaryApi from '../common/SummaryApi'
import Axios from '../utils/Axios'
import AxiosToastError from '../utils/AxiosToastError'
import { DisplayPriceInRupees } from '../utils/DisplayPriceInRupees'
import Divider from '../components/Divider'
import Loading from '../components/Loading'
import { pricewithDiscount } from '../utils/PriceWithDiscount'
import AddToCartButton from '../components/AddToCartButton'
import CategoryWiseProductDisplay from '../components/CategoryWiseProductDisplay'
import ReviewsSection from '../components/ReviewsSection'
import ProductAIChat from '../components/ProductAIChat'
import { getImageUrl } from '../utils/getImageUrl'
import { motion, AnimatePresence } from 'framer-motion'
import toast from "react-hot-toast"
import { useGlobalContext } from '../provider/GlobalProvider'

const ProductDisplay = () => {
  const params = useParams()
  const navigate = useNavigate()
  const { addItemToCart, cartItem } = useGlobalContext()
  const productUrl = params?.product
  const productId = productUrl ? productUrl.split("-").pop() : null

  const [data, setData] = useState({
    name: "",
    image: [],
    video: ""
  })

  const [image, setImage] = useState(0)
  const [loading, setLoading] = useState(false)
  const [reviews, setReviews] = useState([])
  const [reviewLoading, setReviewLoading] = useState(false)
  const [isFullScreen, setIsFullScreen] = useState(false)
  const [showStickyBar, setShowStickyBar] = useState(false)
  const galleryRef = useRef(null)
  const thumbnailRef = useRef(null)
  const modalGalleryRef = useRef(null)
  const mainAddToCartRef = useRef(null)
  const [isMobile, setIsMobile] = useState(false)
  const [pincode, setPincode] = useState("")
  const [isPincodeChecked, setIsPincodeChecked] = useState(false)
  const [pincodeAvailable, setPincodeAvailable] = useState(null)
  const [showOpenBoxModal, setShowOpenBoxModal] = useState(false)
  const [showAllImages, setShowAllImages] = useState(false)

  // Custom active tab state inside details accordion
  const [activeTab, setActiveTab] = useState("SHOWCASE")

  // Custom accordions state
  const [openAccordion, setOpenAccordion] = useState({
    shop: true,
    highlights: false,
    details: false
  })

  const toggleAccordion = (section) => {
    setOpenAccordion(prev => ({
      ...prev,
      [section]: !prev[section]
    }))
  }

  // Filter valid images to prevent extra dots or empty elements
  const validImages = data?.image?.filter(img => typeof img === 'string' && img.trim() !== '') || []
  const hasVideo = !!(data?.video && typeof data.video === 'string' && data.video.trim() !== '' && data.video !== 'null' && data.video !== 'undefined')
  const mediaList = [...(hasVideo ? [data.video] : []), ...validImages]

  const getDeliveryDates = (pin) => {
    const firstDigit = pin ? pin.charAt(0) : '';
    let baseStart = 3;
    let baseEnd = 15;

    if (firstDigit === '1') {
      baseStart = 3;
      baseEnd = 5;
    } else if (firstDigit === '2') {
      baseStart = 4;
      baseEnd = 6;
    } else if (firstDigit === '3') {
      baseStart = 5;
      baseEnd = 7;
    } else if (firstDigit === '4') {
      baseStart = 4;
      baseEnd = 6;
    } else if (firstDigit === '5') {
      baseStart = 3;
      baseEnd = 5;
    } else if (firstDigit === '6') {
      baseStart = 2;
      baseEnd = 4;
    } else {
      baseStart = 3;
      baseEnd = 15;
    }

    let productOffset = 0;
    if (data?._id) {
      const charSum = data._id.split('').reduce((sum, char) => sum + char.charCodeAt(0), 0);
      productOffset = charSum % 3;
    }

    const currentCartItem = cart.find(item => item.productId?._id === data?._id || item.productId === data?._id);
    const currentItemQty = currentCartItem ? currentCartItem.quantity : 0;
    const hasSameItemSpeedup = currentItemQty >= 2;
    const cartQtyOffset = (totalCartQty <= 1 && !hasSameItemSpeedup) ? 3 : 0;

    const startOffset = baseStart + productOffset + cartQtyOffset;
    const startDate = new Date(Date.now() + startOffset * 24 * 60 * 60 * 1000);

    const startStr = startDate.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: '2-digit' }).toUpperCase();

    return {
      range: startStr
    };
  };



  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 1024)
    checkMobile()
    window.addEventListener('resize', checkMobile)
    return () => window.removeEventListener('resize', checkMobile)
  }, [])

  const handleNext = (e) => {
    e.stopPropagation()
    const totalMedia = mediaList.length
    if (totalMedia > 0) {
      setImage((prev) => (prev + 1) % totalMedia)
    }
  }

  const handlePrev = (e) => {
    e.stopPropagation()
    const totalMedia = mediaList.length
    if (totalMedia > 0) {
      setImage((prev) => (prev - 1 + totalMedia) % totalMedia)
    }
  }

  const handleScrollThumbnails = (direction) => {
    if (thumbnailRef.current) {
        const scrollAmount = 200;
        thumbnailRef.current.scrollBy({ 
            left: direction === 'left' ? -scrollAmount : scrollAmount, 
            behavior: 'smooth' 
        });
    }
  }

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        setShowStickyBar(!entry.isIntersecting)
      },
      { threshold: 0 }
    )

    if (mainAddToCartRef.current) {
      observer.observe(mainAddToCartRef.current)
    }

    return () => observer.disconnect()
  }, [])

  const handleScroll = () => {
    if (!galleryRef.current) return
    const scrollLeft = galleryRef.current.scrollLeft
    const width = galleryRef.current.offsetWidth
    const index = Math.round(scrollLeft / width)
    const totalMedia = mediaList.length
    if (index !== image && index >= 0 && index < totalMedia) {
      setImage(index)
    }
  }

  const user = useSelector(state => state?.user)
  const addressList = useSelector(state => state?.addresses?.addressList) || []
  const cart = useSelector(state => state?.cartItem?.cart) || []
  const totalCartQty = cart.reduce((sum, item) => sum + (item.quantity || 1), 0)
  const hasUserReviewed = reviews.some(r => r.userId === user?._id)

  useEffect(() => {
    if (addressList.length > 0 && !pincode) {
      const defaultPin = addressList[0].pincode;
      if (defaultPin && defaultPin.length === 6) {
        setPincode(defaultPin);
        setIsPincodeChecked(true);
        setPincodeAvailable(true);
      }
    }
  }, [addressList]);

  const fetchProductDetails = async () => {
    try {
      setLoading(true)
      const response = await Axios({
        ...SummaryApi.getProductDetails,
        data: { productId }
      })

      if (response.data.success) {
        const productData = response.data.data
        setData({
          ...productData,
          _original: {
            unit: productData.unit,
            price: productData.price,
            mrp: productData.mrp,
            discount: productData.discount,
            stock: productData.stock
          }
        })
      }
    } catch (error) {
      AxiosToastError(error)
    } finally {
      setLoading(false)
    }
  }

  const fetchReviews = async () => {
    if (!productId) return;
    try {
        setReviewLoading(true)
        const response = await Axios(SummaryApi.review_get(productId))
        if (response.data.success) {
            setReviews(response.data.data)
        }
    } catch (error) {
        console.error("Error fetching reviews", error)
    } finally {
        setReviewLoading(false)
    }
  }

  useEffect(() => {
    window.scrollTo(0, 0)
    fetchProductDetails()
    fetchReviews()
  }, [params])

  // Reset selected image and scroll position when details finish loading or product ID changes
  useEffect(() => {
    if (!loading && galleryRef.current) {
      galleryRef.current.scrollLeft = 0
      setImage(0)
    }
  }, [loading, productId])

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href)
    toast.success("Product link copied to clipboard!")
  }

  const handleBuyNow = async (e) => {
    e.preventDefault()
    e.stopPropagation()

    if (!productId) return

    // Combined data for cart
    const activeProductData = {
      ...data,
      unit: data.unit,
      price: data.price,
      mrp: data.mrp,
      discount: data.discount,
      stock: data.stock
    }

    const normalize = (str) => (str || "").toString().replace(/\s+/g, "").toLowerCase()
    const currentUnit = normalize(activeProductData.unit)
    const isInCart = cart?.some(item => {
        const itemProductId = item.productId?._id || item.productId?.id || item.productId
        return itemProductId?.toString() === productId?.toString() && normalize(item.unit) === currentUnit
    })

    if (!isInCart) {
        try {
            await addItemToCart(activeProductData)
        } catch (error) {
            console.error("Error adding to cart:", error)
        }
    }
    navigate("/checkout")
  }

  const baseVariant = data._original ? {
    unit: data._original.unit,
    price: data._original.price,
    mrp: data._original.mrp,
    discount: data._original.discount,
    stock: data._original.stock,
    isOriginal: true
  } : null;

  const otherVariants = (data.variants || [])
    .filter(v => v.unit && v.unit !== data?._original?.unit)
    .map(v => ({ ...v, isOriginal: false }));

  const allVariants = baseVariant ? [baseVariant, ...otherVariants] : [];

  return (
    <>
      <section className='w-full mx-auto pb-32 lg:pb-10 bg-white text-gray-900 transition-colors duration-300 min-h-screen'>
        <div className='flex flex-col lg:grid lg:grid-cols-2 gap-0 lg:gap-16 max-w-7xl mx-auto px-4 lg:px-6'>

            {/* Left Column: Image Gallery */}
            <div className='w-full max-w-full overflow-hidden bg-white mt-4 lg:mt-10'>
                <div className='relative bg-white aspect-square flex items-center justify-center overflow-hidden border border-gray-100 rounded-3xl shadow-sm'>



                    <div 
                        ref={galleryRef}
                        onScroll={handleScroll}
                        className='w-full h-full flex overflow-x-scroll snap-x snap-mandatory no-scrollbar lg:overflow-hidden'
                    >
                        {mediaList.map((item, index) => (
                            <div key={index} className='w-full min-w-full h-full shrink-0 snap-center snap-always flex items-center justify-center p-2 lg:p-14 lg:pt-20'>
                                {hasVideo && index === 0 ? (
                                    <div 
                                        onClick={() => setIsFullScreen(true)}
                                        className='relative w-full h-full bg-black rounded-xl overflow-hidden flex items-center justify-center cursor-pointer'
                                    >
                                        <video 
                                            src={getImageUrl(item)} 
                                            className='w-full h-full object-contain pointer-events-none'
                                            muted
                                            playsInline
                                        />
                                        <div className='absolute inset-0 flex items-center justify-center bg-black/25'>
                                            <div className='w-14 h-14 bg-white/95 rounded-full flex items-center justify-center shadow-lg transition-transform hover:scale-105 active:scale-95'>
                                                <svg className="w-8 h-8 text-green-700 ml-1" fill="currentColor" viewBox="0 0 24 24">
                                                    <path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" />
                                                </svg>
                                            </div>
                                        </div>
                                    </div>
                                ) : (
                                    <img
                                        src={getImageUrl(item)}
                                        onClick={() => setIsFullScreen(true)}
                                        className='w-full h-full object-contain transition-transform duration-500 lg:group-hover:scale-105 cursor-zoom-in'
                                        alt={`${data?.name}-${index}`}
                                    /> 
                                )}
                            </div>
                        ))}
                    </div>

