            >
              <FaTrash size={11} />
              Clear All
            </button>
          )}
        </div>

        {/* ── Empty State ──────────────────────────────────────────────── */}
        {wishlistItems.length === 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="flex flex-col items-center justify-center py-28 text-center"
          >
            <div className="w-28 h-28 rounded-full bg-red-50 border border-red-100 flex items-center justify-center mb-6 shadow-inner">
              <IoHeartDislike className="w-12 h-12 text-red-300" />
            </div>
            <h2 className="text-xl font-black text-gray-800 mb-2 font-luxury-serif">
              Your wishlist is empty
            </h2>
            <p className="text-sm text-gray-400 font-medium mb-8 max-w-xs">
              Tap the heart icon on any product to save it here for later.
            </p>
            <Link
              to="/"
              className="bg-luxury-green-dark hover:bg-luxury-green text-white font-bold px-10 py-3.5 rounded-2xl text-sm uppercase tracking-widest transition-all active:scale-95 shadow-premium"
            >
              Explore Products
            </Link>
          </motion.div>
        )}

        {/* ── Product Grid ─────────────────────────────────────────────── */}
        {wishlistItems.length > 0 && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4 lg:gap-6">
            <AnimatePresence>
              {wishlistItems.map((item) => {
                const url = `/product/${valideURLConvert(item.name)}-${item._id}`
                const discountedPrice = pricewithDiscount(item.price, item.discount)
                const originalPrice   = item.mrp || item.price
                const hasDiscount     = Boolean(item.discount) && discountedPrice < originalPrice

                return (
                  <motion.div
                    key={item._id}
                    layout
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: removing === item._id ? 0 : 1, scale: removing === item._id ? 0.9 : 1 }}
                    exit={{ opacity: 0, scale: 0.9 }}
                    transition={{ duration: 0.25 }}
                    className="group bg-white rounded-3xl border border-gray-100 shadow-premium hover:shadow-[0_8px_30px_rgba(0,0,0,0.10)] transition-all duration-300 overflow-hidden flex flex-col"
                  >
                    {/* Image */}
                    <Link to={url} className="relative aspect-square w-full bg-[#faf9f6] flex items-center justify-center p-4 overflow-hidden">
                      <img
                        src={getImageUrl(item.image?.[0])}
                        alt={item.name}
                        className="w-full h-full object-contain transition-transform duration-500 group-hover:scale-[1.05]"
                      />

                      {/* Discount Badge */}
                      {hasDiscount && (
                        <div className="absolute top-3 left-3 w-10 h-10 rounded-full bg-luxury-gold-gradient text-white flex flex-col items-center justify-center leading-none shadow-premium z-10 select-none pointer-events-none border border-white/20">
                          <span className="text-[10px] font-black">{item.discount}%</span>
                          <span className="text-[6.5px] font-black uppercase">OFF</span>
                        </div>
                      )}

                      {/* Remove from Wishlist */}
                      <button
                        onClick={(e) => { e.preventDefault(); e.stopPropagation(); handleRemove(item) }}
                        className="absolute top-3 right-3 z-20 w-9 h-9 rounded-full bg-white border border-red-100 flex items-center justify-center shadow-sm hover:scale-110 hover:border-red-300 active:scale-90 transition-all cursor-pointer"
                      >
                        <FaHeart className="w-4 h-4 text-red-500" />
                      </button>
                    </Link>

                    {/* Content */}
                    <div className="flex flex-col flex-1 p-4">
                      <Link to={url}>
                        <h3 className="text-[12.5px] lg:text-[13.5px] font-bold text-slate-800 line-clamp-2 leading-snug mb-2 tracking-tight group-hover:text-luxury-green-dark transition-colors">
                          {item.name}
                        </h3>
                      </Link>

                      {item.unit && (
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mb-3">
                          {item.unit}
                        </p>
                      )}

                      {/* Price */}
                      <div className="mb-3">
                        <p className="text-[17px] lg:text-[19px] font-black text-luxury-green-dark leading-none">
                          {DisplayPriceInRupees(discountedPrice)}
                        </p>
                        {hasDiscount && (
                          <p className="text-[11px] text-gray-400 font-semibold line-through mt-1">
                            {DisplayPriceInRupees(originalPrice)}
                          </p>
                        )}
                      </div>

                      {/* Stock */}
                      {Number(item.stock) > 0 ? (
                        <div className="flex items-center gap-1.5 bg-emerald-50 text-luxury-green px-3 py-1 rounded-full text-[9px] font-black tracking-wider border border-emerald-100/60 w-fit mb-4">
                          <span className="w-1.5 h-1.5 rounded-full bg-luxury-green" />
                          <span>IN STOCK</span>
                        </div>
                      ) : (
                        <div className="flex items-center gap-1.5 bg-red-50 text-red-600 px-3 py-1 rounded-full text-[9px] font-black tracking-wider border border-red-100/60 w-fit mb-4">
                          <span className="w-1.5 h-1.5 rounded-full bg-red-500" />
                          <span>OUT OF STOCK</span>
                        </div>
                      )}

                      {/* CTA */}
                      <div
                        className="mt-auto"
                        onClick={e => { e.preventDefault(); e.stopPropagation() }}
                      >
                        {Number(item.stock) > 0 ? (
                          <AddToCartButton data={item} variant="orange-full" />
                        ) : (
                          <button
                            disabled
                            className="w-full h-10 bg-gray-100 text-gray-400 font-semibold rounded-2xl text-xs flex items-center justify-center cursor-not-allowed select-none"
                          >
                            Out of Stock
                          </button>
                        )}
                      </div>
                    </div>
                  </motion.div>
                )
              })}
            </AnimatePresence>
          </div>
        )}

        {/* ── Continue Shopping ───────────────────────────────────────── */}
        {wishlistItems.length > 0 && (
          <div className="mt-14 text-center">
            <Link
              to="/"
              className="inline-flex items-center gap-2 text-sm font-bold text-luxury-green-dark hover:text-luxury-green border border-luxury-green-dark/20 hover:border-luxury-green/40 bg-white px-8 py-3 rounded-2xl transition-all active:scale-95 shadow-3xs"
            >
              ← Continue Shopping
            </Link>
          </div>
        )}
      </div>
    </div>
  )
}

export default Wishlist

import { createContext, useContext, useEffect, useState } from "react";
import Axios from "../utils/Axios";
import SummaryApi from "../common/SummaryApi";
import { useDispatch, useSelector } from "react-redux";
import {
  clearCartItem,
  handleAddItemCart,
  updateCartItemQtyOptimistic,
  addCartItemOptimistic,
} from "../store/cartProduct";

import toast from "react-hot-toast";
import { pricewithDiscount } from "../utils/PriceWithDiscount";
import { clearAddress, handleAddAddress } from "../store/addressSlice";
import { clearOrder, setOrder } from "../store/orderSlice";
import { setUserDetails } from "../store/userSlice";

export const GlobalContext = createContext(null);
export const useGlobalContext = () => useContext(GlobalContext);

const GlobalProvider = ({ children }) => {
  const dispatch = useDispatch();

  const [totalPrice, setTotalPrice] = useState(0);
  const [notDiscountTotalPrice, setNotDiscountTotalPrice] = useState(0);
  const [totalQty, setTotalQty] = useState(0);
  const [deliveryCharge, setDeliveryCharge] = useState(0);
  const [handlingCharge, setHandlingCharge] = useState(0);
  const [couponDiscount, setCouponDiscount] = useState(0);
  const [appliedCoupon, setAppliedCoupon] = useState(null);

  const cartItem = useSelector((state) => state.cartItem.cart);
  const user = useSelector((state) => state?.user);

  // ✅ FETCH USER
  const fetchUser = async () => {
    try {
      const response = await Axios({
        ...SummaryApi.userDetails,
      });
      const { data: responseData } = response;
      if (responseData.success) {
        dispatch(setUserDetails(responseData.data));
      }
    } catch (error) {
      console.log("Error fetching user details:", error);
    }
  };

  // ✅ FETCH CART
  const fetchCartItem = async () => {
    try {
      const response = await Axios({
        ...SummaryApi.getCartItem,
      });

      const { data: responseData } = response;

      if (responseData.success) {
        dispatch(handleAddItemCart(responseData.data));
      }
    } catch (error) {
      console.log("Error fetching cart items:", error);
    }
  };

  // ✅ ADD ITEM TO CART
  const addItemToCart = async (product) => {
      if(!product?._id) return;
      
      // ⚡ 1. OPTIMISTIC RENDER: Create synthetic temporary cart item and push immediately!
      const tempId = "temp_" + Date.now();
      const syntheticItem = {
          _id: tempId,
          productId: product, // Object containing details needed by components
          quantity: 1,
          unit: product.unit || ""
      };
      
      dispatch(addCartItemOptimistic(syntheticItem));

      try {
          const response = await Axios({
              ...SummaryApi.addTocart,
              data: {
                  productId: product._id.toString(),
                  unit: product.unit?.toString() || ""
              }
          });

          const { data: responseData } = response;
          
          // Always refresh true state from DB once settled to finalize correct IDs
          fetchCartItem(); 
          
          return responseData;
      } catch (error) {
          fetchCartItem(); // Revert synthetic UI on error by hard refresh
          throw error;
      }
  };

  // ✅ UPDATE CART QTY
  const updateCartItem = async (id, qty) => {
    // 🚀 OPTIMISTIC UI UPDATE: Push instantly so UI reacts in 1ms
    dispatch(updateCartItemQtyOptimistic({ _id: id, qty: qty }));

    try {
      const response = await Axios({
        ...SummaryApi.updateCartItemQty,
        data: {
          _id: id,
          qty: qty,
        },
      });

      const { data: responseData } = response;

      if (responseData.success) {
        // No need to do an extra network hit fetchCartItem() anymore!
        return responseData;
      } else {
          // If backend explicitly rejects (e.g., stock issue), revert to truth
          fetchCartItem();
      }
    } catch (error) {
      // On network failure, revert UI
      fetchCartItem();
      throw error;
    }
  };

  // ✅ DELETE CART ITEM
  const deleteCartItem = async (cartId) => {
    try {
      const response = await Axios({
        ...SummaryApi.deleteCartItem,
        data: {
          _id: cartId,
        },
      });

      const { data: responseData } = response;

      if (responseData.success) {
        toast.success(responseData.message);
        fetchCartItem();
      }
    } catch (error) {
      throw error;
    }
  };

  // ✅ CALCULATIONS
  useEffect(() => {
    if (!cartItem || !Array.isArray(cartItem)) return;

    // Filter valid items once for all calculations
    const validItems = cartItem.filter(item => item?.productId);

    // Total Quantity
    const qty = validItems.reduce((prev, curr) => prev + (curr.quantity || 0), 0);
    setTotalQty(qty);

    // Subtotal (with product discount)
    const subtotal = validItems.reduce((prev, curr) => {
      let price = curr?.productId?.price || 0;
      let discount = curr?.productId?.discount || 0;

      // If item is a variant, find its specific price/discount
      if (curr.unit && curr.unit !== curr.productId?.unit) {
        const variant = curr.productId?.variants?.find(v => v.unit === curr.unit);
        if (variant) {
          price = variant.price;
          discount = variant.discount;
        }
      }

      const priceAfterDiscount = pricewithDiscount(price, discount);
      return prev + priceAfterDiscount * (curr.quantity || 0);
    }, 0);
    setTotalPrice(subtotal);

    // Total without any discount (for comparison)
    const originalPrice = validItems.reduce((prev, curr) => {
      let price = curr?.productId?.price || 0;
      if (curr.unit && curr.unit !== curr.productId?.unit) {
        const variant = curr.productId?.variants?.find(v => v.unit === curr.unit);
        if (variant) price = variant.price;
      }
      return prev + price * (curr.quantity || 0);
    }, 0);
    setNotDiscountTotalPrice(originalPrice);

    // Charges logic
    if (qty > 0) {
      setDeliveryCharge(subtotal < 199 ? 30 : 0);
      setHandlingCharge(subtotal > 199 ? 9 : 0);
    } else {
      setDeliveryCharge(0);
      setHandlingCharge(0);
    }

    // Reset coupon if minAmount not met
    if (appliedCoupon && subtotal < (appliedCoupon.minAmount || 0)) {
        setAppliedCoupon(null);
        setCouponDiscount(0);
        toast.error(`Coupon removed: Minimum order of ₹${appliedCoupon.minAmount} required`);
    } else if (appliedCoupon) {
        let discount = Math.ceil((subtotal * appliedCoupon.discountPercent) / 100);
        if (appliedCoupon.maxDiscount && discount > appliedCoupon.maxDiscount) {
            discount = appliedCoupon.maxDiscount;
        }
        setCouponDiscount(discount);
    } else {
        setCouponDiscount(0);
    }
  }, [cartItem, appliedCoupon]);

  // ✅ FETCH ADDRESS
  const fetchAddress = async () => {
    try {
      const response = await Axios({
        ...SummaryApi.getAddress,
      });

      const { data: responseData } = response;

      if (responseData.success) {
        dispatch(handleAddAddress(responseData.data));
      }
    } catch (error) {}
  };

  // ✅ FETCH ORDERS
  const fetchOrder = async () => {
    try {
      const response = await Axios({
        ...SummaryApi.getOrderItems,
      });

      const { data: responseData } = response;

      if (responseData.success) {
        dispatch(setOrder(responseData.data));
      }
    } catch (error) {
      console.log(error);
    }
  };

  // ✅ INITIAL LOAD
  useEffect(() => {
    if (!user?._id) {
      dispatch(clearCartItem());
      dispatch(clearAddress());
      dispatch(clearOrder());
      return;
    }

    fetchCartItem();
    fetchAddress();
    fetchOrder();
  }, [user]);

  // 🔥🔥🔥 NEW: LISTEN FOR CART UPDATE EVENT
  useEffect(() => {
    const handleCartUpdate = () => {
      fetchCartItem();
    };

    window.addEventListener("cartUpdated", handleCartUpdate);

    return () => {
      window.removeEventListener("cartUpdated", handleCartUpdate);
    };
  }, []);

  return (
    <GlobalContext.Provider
      value={{
        fetchCartItem,
        addItemToCart,
        updateCartItem,
        deleteCartItem,
        deliveryCharge,
        handlingCharge,
        couponDiscount,
        appliedCoupon,
        setAppliedCoupon,
        totalPrice,
        totalQty,
        notDiscountTotalPrice,
        fetchOrder,
        fetchUser,
        fetchAddress,
      }}
    >
      {children}
    </GlobalContext.Provider>
  );
};

export default GlobalProvider;

import { createSlice } from '@reduxjs/toolkit';

// Persist wishlist in localStorage
const loadFromStorage = () => {
  try {
    const raw = localStorage.getItem('wishlist');
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
};

const saveToStorage = (items) => {
  try {
    localStorage.setItem('wishlist', JSON.stringify(items));
  } catch {}
};

const wishlistSlice = createSlice({
  name: 'wishlist',
  initialState: {
    items: loadFromStorage(),
  },
  reducers: {
    addToWishlist: (state, action) => {
      const exists = state.items.some(i => i._id === action.payload._id);
      if (!exists) {
        state.items.push(action.payload);
        saveToStorage(state.items);
      }
    },
    removeFromWishlist: (state, action) => {
      state.items = state.items.filter(i => i._id !== action.payload);
      saveToStorage(state.items);
    },
    toggleWishlist: (state, action) => {
      const idx = state.items.findIndex(i => i._id === action.payload._id);
      if (idx === -1) {
        state.items.push(action.payload);
      } else {
        state.items.splice(idx, 1);
      }
      saveToStorage(state.items);
    },
    clearWishlist: (state) => {
      state.items = [];
      saveToStorage([]);
    },
  },
});

export const { addToWishlist, removeFromWishlist, toggleWishlist, clearWishlist } = wishlistSlice.actions;
export default wishlistSlice.reducer;

